import sys
from collections import deque

def build_tree(tokens):
    n = len(tokens)
    nodes = [None] * n
    for i, t in enumerate(tokens):
        if t != 'NULL':
            nodes[i] = {'val': int(t), 'left': None, 'right': None}
    for i in range(n):
        if nodes[i] is None:
            continue
        l = 2 * i + 1
        r = 2 * i + 2
        if l < n:
            nodes[i]['left'] = nodes[l]
        if r < n:
            nodes[i]['right'] = nodes[r]
    return nodes[0] if n else None

sys.setrecursionlimit(10**6)

def dfs(node):
    if node is None:
        return 0
    left = max(0, dfs(node['left']))
    right = max(0, dfs(node['right']))
    dfs.max_sum = max(dfs.max_sum, node['val'] + left + right)
    return node['val'] + max(left, right)


def solve():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        tokens = next(it).split()
        root = build_tree(tokens)
        dfs.max_sum = -10**9
        dfs(root)
        out.append(str(dfs.max_sum))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

